"use client";

import { useAuth } from "@/hooks/useAuth";
import { useState, useEffect } from "react";
import client from "@/api/client";
import MealkitList from "@/components/MealkitList";

import type { Recipe } from "@/types/types";

export default function Dashboard() {
  const { user } = useAuth();

  const [username, setUsername] = useState("");
  const [recipes, setRecipes] = useState<Recipe[]>([]);

  useEffect(() => {
    async function getUsername() {
      const userId = user?.id;
      if (!user) return;

      const { data, error } = await client
        .from("users")
        .select("username")
        .eq("auth_id", userId)
        .maybeSingle();

      console.log(data);
      console.log(error);

      if (error) {
        console.log("An error happened: ", error.message);
        return;
      }

      if (data) {
        setUsername(data.username);
      }
    }

    getUsername();
  }, [user]);

  useEffect(() => {
    const getRecipes = async () => {
      const { data, error } = await client.from("recipes").select("*");

      if (error) {
        console.error(error);
        return;
      }

      setRecipes(data);
    };

    getRecipes();
  }, []);

  return (
    <div>
      <div>
        <h1 className="text-5xl font-semibold mt-2 place-self-center">
          Welcome, {username}!
        </h1>
        <h2 className="text-2xl font-semibold mt-2 place-self-center">
          See what&apos;s available on the menu
        </h2>
      </div>

      <div className="grid grid-cols-6 w-1/2 place-self-center mt-10 rounded-xl overflow-hidden border-2 border-black">
        <button className="h-15 transition duration-100 hover:bg-black hover:text-white">
          M
        </button>
        <button className="h-15 transition duration-100 hover:bg-black hover:text-white">
          T
        </button>
        <button className="h-15 transition duration-100 hover:bg-black hover:text-white">
          W
        </button>
        <button className="h-15 transition duration-100 hover:bg-black hover:text-white">
          T
        </button>
        <button className="h-15 transition duration-100 hover:bg-black hover:text-white">
          F
        </button>
        <button className="h-15 transition duration-100 hover:bg-black hover:text-white">
          S
        </button>
      </div>

      <MealkitList recipes={recipes} />
    </div>
  );
}
